import{_ as s,C as t,o as h,c,j as e,a as n,E as i,a3 as m}from"./chunks/framework.CVjg771q.js";const q=JSON.parse('{"title":"帛书第7章 立戒","description":"帛书德篇第7章 · 立戒（通行本第44章）","frontmatter":{"title":"帛书第7章 立戒","description":"帛书德篇第7章 · 立戒（通行本第44章）","category":"guide","aliases":["帛书第7章","马王堆老子7","通行本第44章"],"source":["马王堆汉墓帛书《老子》甲本"]},"headers":[],"relativePath":"daoism/texts/dao-de-jing-boshu/chapter-07.md","filePath":"daoism/texts/dao-de-jing-boshu/chapter-07.md","lastUpdated":1779783531000}'),p={name:"daoism/texts/dao-de-jing-boshu/chapter-07.md"};function u(x,a,b,g,_,f){const o=t("DaoReadingPrelude"),r=t("DaoOriginalReading"),l=t("DaoLineGuide"),d=t("DaoKeywordCards");return h(),c("div",null,[a[0]||(a[0]=e("h1",{id:"帛书老子第7章",tabindex:"-1"},[n("帛书老子第7章 "),e("a",{class:"header-anchor",href:"#帛书老子第7章","aria-label":'Permalink to "帛书老子第7章"'},"​")],-1)),i(o,{title:"第7章 立戒",summary:"本章出自马王堆帛书《老子》甲本德篇，对应通行本第44章。帛书本德篇在前、道篇在后，文字多作「亓」「恒」「邦」等古字，反映了更早的写本面貌。",points:[{label:"底本",text:"马王堆帛书甲本 · 德篇第7章"},{label:"对照",text:"通行本第44章，注意篇序与文字差异"},{label:"读法",text:"初读先顺原文；再读可对照通行本逐句比对异同。"}],hint:'帛书甲本是现存最早的《老子》完整写本之一。文中括号注如「泊（薄）」表示帛书作"泊"，校读为"薄"。'}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[n("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),i(r,{paragraphs:["名与身孰亲 身与货孰多 得与亡孰病","甚爱必大费 多藏必厚亡","故知足不辱 知止不殆 可以长久"]}),i(l,{lines:[{text:"名与身孰亲 身与货孰多 得与亡孰病",tone:"起",guide:"名声与身体哪个更亲近？身体与财货哪个更重要？得到与失去哪个更有害？三连追问，直指人生最根本的价值排序。"},{text:"甚爱必大费 多藏必厚亡",tone:"理",guide:"过分吝惜必定导致巨大的耗费，过多收藏必定导致惨重的损失——越是想守住，越会失去。"},{text:"故知足不辱 知止不殆 可以长久",tone:"收",guide:"所以知道满足就不会受辱，知道停止就不会危险，这样才能长久。知足、知止——老子给出的两剂人生良药。"}]}),a[2]||(a[2]=e("h2",{id:"【原典层】字词释义",tabindex:"-1"},[n("【原典层】字词释义 "),e("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),i(d,{items:[{term:"孰",pinyin:["shú"],meaning:"哪个、谁。名与身孰亲——名声和身体，哪个更亲近？帛书三问层层递进，直指人生最根本的价值排序。",context:"名与身、身与货、得与亡——三问如三记重锤。"},{term:"病",pinyin:["bìng"],meaning:"有害、糟糕。得与亡孰病——得到与失去，哪个更有害？帛书将「病」字用于终极追问：我们拼命追求的东西，可能比失去还要糟糕。",context:"天之道利而不害，人之道则常以利为病、以病为利。"},{term:"爱",pinyin:["ài"],meaning:"吝惜、舍不得。甚爱必大费——越是吝惜，越是舍不得，最终反而付出更大的代价。帛书之「爱」非仁爱之爱，而是执着不放的贪恋。",context:"与「多藏必厚亡」对举——爱之愈甚，失之愈惨。"},{term:"大费",pinyin:["dà","fèi"],meaning:"巨大的耗费与损失。甚爱必大费——过分吝惜必定导致巨大的耗费。帛书揭示「爱」与「费」之间的悖论：越想守住，失去的越多。",context:"「大费」是爱的反噬——爱惜到了一定程度，就开始消耗自己。"},{term:"厚亡",pinyin:["hòu","wáng"],meaning:"惨重的损失。多藏必厚亡——藏得越多，失去得越惨重。",context:"与「甚爱必大费」对举，是老子对贪求者的严厉警告。"},{term:"知止不殆",pinyin:["zhī","zhǐ","bù","dài"],meaning:"知道适可而止就不会有危险。知足不辱，知止不殆——帛书给出两剂人生良药：知足则不受辱，知止则不遇险。",context:"「不殆」不是消极的不犯错，而是主动避开危险的智慧——老子不是让人不做事，而是让人知道在哪里停下。"}]}),a[3]||(a[3]=m('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一章在说什么" tabindex="-1">象：这一章在说什么 <a class="header-anchor" href="#象-这一章在说什么" aria-label="Permalink to &quot;象：这一章在说什么&quot;">​</a></h3><p>本章标题为「立戒」，帛书此章围绕「名身货亡」展开。帛书甲本以古字「亓」「恒」「邦」「靓」等呈现了比通行本更早的文本面貌，读者在阅读时需要注意这些古字的含义及与通行本的对应关系。</p><h3 id="理-为什么这样说" tabindex="-1">理：为什么这样说 <a class="header-anchor" href="#理-为什么这样说" aria-label="Permalink to &quot;理：为什么这样说&quot;">​</a></h3><p>本章在帛书《老子》中的重要性体现在：其一，文本上保留了战国至汉初的古字写法，是考证《老子》流传演变的重要实物；其二，义理上与通行本基本一致但用字更古，某些关键概念（如恒vs常、邦vs国）的差异反映了思想史的重要变化；其三，作为现存最早的《老子》完整写本之一，每章都是理解老子原始思想的珍贵窗口。</p><h3 id="用-这一章今天怎么用" tabindex="-1">用：这一章今天怎么用 <a class="header-anchor" href="#用-这一章今天怎么用" aria-label="Permalink to &quot;用：这一章今天怎么用&quot;">​</a></h3><p>今天读这一章，建议分两步。第一步，先顺读原文，感受帛书古朴的文字气息。第二步，对照通行本对应章节（括号中标注），体会异文带来的理解差异。帛书本提醒我们：经典文本从来不是凝固不变的——每一次抄写，都可能是一次微小的诠释。这种对文本流动性的感知，本身就是一种珍贵的学习体验。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>待整理。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>待整理。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>马王堆汉墓帛书《老子》甲本（底本）</li><li>对应通行本第44章，所属帛书德篇</li><li>高明《帛书老子校注》</li><li>国家文物局古文献研究室《马王堆汉墓帛书（壹）》</li></ul>',13))])}const k=s(p,[["render",u]]);export{q as __pageData,k as default};
